$schema                           : @{description=JSON Schema reference for Claude Code settings; type=string; 
                                    const=https://json.schemastore.org/claude-code-settings.json}
apiKeyHelper                      : @{description=Path to a script that outputs authentication values; type=string}
proxyAuthHelper                   : @{description=Shell command that outputs a Proxy-Authorization header value (EAP); 
                                    type=string}
awsCredentialExport               : @{description=Path to a script that exports AWS credentials; type=string}
awsAuthRefresh                    : @{description=Path to a script that refreshes AWS authentication; type=string}
gcpAuthRefresh                    : @{description=Command to refresh GCP authentication (e.g., gcloud auth 
                                    application-default login); type=string}
policyHelper                      : @{description=Executable that computes managed settings at startup. Honored only 
                                    from admin-controlled policy sources.; type=object; properties=; 
                                    required=System.Object[]}
fileSuggestion                    : @{description=Custom file suggestion configuration for @ mentions; type=object; 
                                    properties=; required=System.Object[]}
respectGitignore                  : @{description=Whether file picker should respect .gitignore files (default: true). 
                                    Note: .ignore files are always respected.; type=boolean}
cleanupPeriodDays                 : @{description=Number of days to retain chat transcripts before automatic cleanup 
                                    (default: 30). Minimum 1. Use a large value for long retention; use 
                                    --no-session-persistence to disable transcript writes entirely.; type=integer; 
                                    exclusiveMinimum=0; maximum=9007199254740991}
skillListingMaxDescChars          : @{description=Per-skill description character cap in the skill listing sent to 
                                    Claude (default: 1536). Descriptions longer than this are truncated. Raise to opt 
                                    in to higher per-turn context cost.; type=integer; exclusiveMinimum=0; 
                                    maximum=9007199254740991}
skillListingBudgetFraction        : @{description=Fraction of the context window (in characters) reserved for the 
                                    skill listing sent to Claude (default: 0.01 = 1%). When the listing exceeds this, 
                                    descriptions are shortened to fit. Raise to opt in to higher per-turn context 
                                    cost.; type=number; exclusiveMinimum=0; maximum=1}
wslInheritsWindowsSettings        : @{description=When set to true in either admin-only Windows source ג€” the HKLM 
                                    SOFTWARE/Policies/ClaudeCode registry key or C:/Program 
                                    Files/ClaudeCode/managed-settings.json ג€” WSL reads managed settings from the 
                                    full Windows policy chain (HKLM, C:/Program Files/ClaudeCode via DrvFs, HKCU) in 
                                    addition to /etc/claude-code. Windows sources take priority. The flag is also 
                                    required in HKCU itself for HKCU policy to apply on WSL (double opt-in: admin 
                                    enables the chain, user confirms HKCU). On native Windows the flag has no effect.; 
                                    type=boolean}
env                               : @{description=Environment variables to set for Claude Code sessions; type=object; 
                                    propertyNames=; additionalProperties=}
attribution                       : @{description=Customize attribution text for commits and PRs. Each field defaults 
                                    to the standard Claude Code attribution if not set.; type=object; properties=}
includeCoAuthoredBy               : @{description=Deprecated: Use attribution instead. Whether to include Claude's 
                                    co-authored by attribution in commits and PRs (defaults to true); type=boolean}
includeGitInstructions            : @{description=Include built-in commit and PR workflow instructions in Claude's 
                                    system prompt (default: true); type=boolean}
permissions                       : @{description=Tool usage permissions configuration; type=object; properties=; 
                                    additionalProperties=}
model                             : @{description=Override the default model used by Claude Code; type=string}
fallbackModel                     : @{description=Fallback model(s) tried in order when the primary model is 
                                    overloaded or unavailable. Each element accepts a model name or alias; "default" 
                                    expands to the default model. CLI --fallback-model takes precedence.; type=array; 
                                    items=}
availableModels                   : @{description=Allowlist of models that users can select. Accepts family aliases 
                                    ("opus" allows any opus version), version prefixes ("opus-4-5" allows only that 
                                    version), and full model IDs. If undefined, all models are available. If empty 
                                    array, only the default model is available. Typically set in managed settings by 
                                    enterprise administrators.; type=array; items=}
modelOverrides                    : @{description=Override mapping from Anthropic model ID (e.g. "claude-opus-4-6") to 
                                    provider-specific model ID (e.g. a Bedrock inference profile ARN). Typically set 
                                    in managed settings by enterprise administrators.; type=object; propertyNames=; 
                                    additionalProperties=}
enableAllProjectMcpServers        : @{description=Whether to automatically approve all MCP servers in the project; 
                                    type=boolean}
enabledMcpjsonServers             : @{description=List of approved MCP servers from .mcp.json; type=array; items=}
disabledMcpjsonServers            : @{description=List of rejected MCP servers from .mcp.json; type=array; items=}
skillOverrides                    : @{description=Per-skill listing overrides keyed by skill name. "name-only" lists 
                                    the skill without its description; "user-invocable-only" hides it from the model 
                                    but keeps /name; "off" hides it from both. Absent = on.; type=object; 
                                    propertyNames=; additionalProperties=}
allowedMcpServers                 : @{description=Enterprise allowlist of MCP servers that can be used. Applies to all 
                                    scopes including enterprise servers from managed-mcp.json. If undefined, all 
                                    servers are allowed. If empty array, no servers are allowed. Denylist takes 
                                    precedence - if a server is on both lists, it is denied.; type=array; items=}
deniedMcpServers                  : @{description=Enterprise denylist of MCP servers that are explicitly blocked. If a 
                                    server is on the denylist, it will be blocked across all scopes including 
                                    enterprise. Denylist takes precedence over allowlist - if a server is on both 
                                    lists, it is denied.; type=array; items=}
hooks                             : @{description=Custom commands to run before/after tool executions; type=object; 
                                    propertyNames=; additionalProperties=}
worktree                          : @{description=Git worktree configuration for --worktree flag.; type=object; 
                                    properties=}
disableAllHooks                   : @{description=Disable all hooks and statusLine execution; type=boolean}
disableAgentView                  : @{description=Disable agent view (`claude agents`, `--bg`, /background, the 
                                    on-demand daemon). Typically set in managed settings. Equivalent to 
                                    CLAUDE_CODE_DISABLE_AGENT_VIEW=1.; type=boolean}
disableRemoteControl              : @{description=Disable Remote Control (claude.ai/code, `claude remote-control`, 
                                    `--remote-control`/`--rc`, auto-start, and the in-session toggle). Typically set 
                                    in managed settings.; type=boolean}
disableWorkflows                  : @{description=Disable the Workflows feature (also via 
                                    CLAUDE_CODE_DISABLE_WORKFLOWS).; type=boolean}
enableWorkflows                   : @{description=Enable or disable the Workflows feature for this user. Unset = 
                                    default by plan once the feature is available.; type=boolean}
workflowKeywordTriggerEnabled     : @{description=Enable the "ultracode" keyword trigger: including the keyword in a 
                                    prompt opts that turn into the Workflow tool. Set to false to disable the trigger. 
                                    Default: true.; type=boolean}
disableSkillShellExecution        : @{description=Disable inline shell execution in skills and custom slash commands 
                                    from user, project, or plugin sources. Commands are replaced with a placeholder 
                                    instead of being run.; type=boolean}
defaultShell                      : @{description=Default shell for input-box ! commands. Defaults to 'bash' on all 
                                    platforms (no Windows auto-flip).; type=string; enum=System.Object[]}
allowManagedHooksOnly             : @{description=When true (and set in managed settings), only hooks from managed 
                                    settings run. User, project, and local hooks are ignored.; type=boolean}
allowedHttpHookUrls               : @{description=Allowlist of URL patterns that HTTP hooks may target. Supports * as 
                                    a wildcard (e.g. "https://hooks.example.com/*"). When set, HTTP hooks with 
                                    non-matching URLs are blocked. If undefined, all URLs are allowed. If empty array, 
                                    no HTTP hooks are allowed. Arrays merge across settings sources (same semantics as 
                                    allowedMcpServers).; type=array; items=}
httpHookAllowedEnvVars            : @{description=Allowlist of environment variable names HTTP hooks may interpolate 
                                    into headers. When set, each hook's effective allowedEnvVars is the intersection 
                                    with this list. If undefined, no restriction is applied. Arrays merge across 
                                    settings sources (same semantics as allowedMcpServers).; type=array; items=}
allowManagedPermissionRulesOnly   : @{description=When true (and set in managed settings), only permission rules 
                                    (allow/deny/ask) from managed settings are respected. User, project, local, and 
                                    CLI argument permission rules are ignored.; type=boolean}
allowManagedMcpServersOnly        : @{description=When true (and set in managed settings), allowedMcpServers is only 
                                    read from managed settings. deniedMcpServers still merges from all sources, so 
                                    users can deny servers for themselves. Users can still add their own MCP servers, 
                                    but only the admin-defined allowlist applies.; type=boolean}
allowAllClaudeAiMcps              : @{description=When true (and set in managed settings), claude.ai cloud MCP 
                                    connectors load alongside managed-mcp.json instead of being suppressed by its 
                                    exclusive-control lockdown. Default off preserves the lockdown. Read from managed 
                                    settings only.; type=boolean}
strictPluginOnlyCustomization     : @{description=When set in managed settings, blocks non-plugin customization 
